//   founderScore === null (no scores.axis='founder_score' row for any of this
//   application's current founders) -> return null. The caller must then
//   write NO scores(axis='founder') row at all (§6.0/§6.6: absent base means
//   not-assessed, never a manufactured zero).
function founderAxisScore({ founderScore = null, fmf = 0, maturity = 0 } = {}) {
  if (founderScore === null || founderScore === undefined) return null;
  return clamp(0, 100, founderScore + fmf + maturity);
}

